window,document,(new class{constructor(){this.utmParams=["utm_campaign","utm_medium","utm_source","utm_content"],this.queryString=this.getQueryString(),this.paramsPresent=!1}init(){0<this.queryString.length&&(this.paramsPresent=this.checkForUTMParams(this.queryString),this.paramsPresent)&&(this.clearUTMCookies(),this.maybeSetUTMCookies(this.queryString))}clearUTMCookies(){for(let e=0;e<this.utmParams.length;e++)this.removeUTMCookie(this.utmParams[e])}removeUTMCookie(e){try{return document.cookie=e+"=; max-age=0; path=/",document.cookie}catch(e){return!1}}checkForUTMParams(e){var t=new URLSearchParams(e);for(let e=0;e<this.utmParams.length;e++)if(t.has(this.utmParams[e])){this.paramsPresent=!0;break}return this.paramsPresent}maybeSetUTMCookies(e){var t,r;for([t,r]of new URLSearchParams(e).entries())this.utmParams.includes(t)&&this.setUTMCookie(t,r)}getQueryString(){return window.location.search}setUTMCookie(e,t){t=decodeURIComponent(t),t=encodeURIComponent(t);try{return document.cookie=e+"="+t+"; max-age=259200; path=/",document.cookie}catch(e){return!1}}}).init();